VALUES
  ('fire-eq-tech-moex-00065', 'fire-eq-tech', 'fire-eq-tech-moex-114-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '某工廠現有建築物及儲存場所之中度危險工作場所樓地板面積合計 2,000 平方公尺，該工廠 將擴廠增建一棟一樓層之低度危險工作場所，該增建場所之建築物及儲存場所樓地板面積合 計在多少平方公尺以上時，應設置室外消防栓設備？', '["3,000", "5,000", "6,000", "8,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "175e5c35db4c", "answer_pdf_sha1": "f7df6e4dab9e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00066', 'fire-eq-tech', 'fire-eq-tech-moex-114-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '消防設備人員依消防安全設備及必要檢修項目檢修基準規定，執行室內消防栓設備檢修之綜 合檢查。下列檢查方法及判定方法，何者錯誤？', '["應切換成緊急電源供電之狀態，於裝置消防栓最多之最高樓層做放水試驗，以該樓層全部 消防栓放水為準。但消防栓超過2支時，以2支同時放水", "公共危險物品等場所達顯著滅火困難者設置消防栓之數量超過5支時，以5支同時放水， 其放水量應在260l/min以上", "消防栓放水壓力應在1.7kgf/cm2以上7kgf/cm2以下", "公共危險物品等場所達顯著滅火困難者設置之第一種滅火設備之消防栓，其放水壓力應在"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "175e5c35db4c", "answer_pdf_sha1": "f7df6e4dab9e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00067', 'fire-eq-tech', 'fire-eq-tech-moex-114-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '5kgf/cm2以上7kgf/cm2以下', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "175e5c35db4c", "answer_pdf_sha1": "f7df6e4dab9e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00068', 'fire-eq-tech', 'fire-eq-tech-moex-114-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依消防設備人員法規定，下列敘述何者錯誤？', '["未依法取得消防設備人員證書，擅自執行業務者處新臺幣10萬元以上100萬元以下罰鍰", "無正當理由，洩漏因業務所知悉或持有他人之秘密者，處新臺幣5萬元以上25萬元以下罰鍰", "直轄市、縣（市）消防設備師公會（士）公會拒絕消防設備人員加入公會者，處新臺幣5萬 元以上25萬元以下罰鍰", "未依規定請領執業執照，或執業執照經撤銷或廢止，仍執行業務者，處新臺幣3萬元以上 15萬元以下罰鍰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "175e5c35db4c", "answer_pdf_sha1": "f7df6e4dab9e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00069', 'fire-eq-tech', 'fire-eq-tech-moex-114-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依避難器具支固器具及固定部之結構、強度計算及施工方法規定，有關斜降式救助袋之下部 支撐裝置固定在降落面等器具之構造、強度及埋設到降落面之方法，下列敘述何者錯誤？', '["固定器具需設在具有蓋子之箱子內部，設置可輕易鉤到下部支撐裝置大小之環或橫棒", "固定橫棒需具備足夠寬度使下部支撐裝置之鉤子可輕易鉤住，且有防止拉拔措施", "蓋子在使用時，其結構應可輕易打開，為防止遺失並應有鍊條連接，且其表面應以不易磨 滅方式標示救助袋設置之樓層", "固定部展開救助袋時，與降落面角度約為45度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "175e5c35db4c", "answer_pdf_sha1": "f7df6e4dab9e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00070', 'fire-eq-tech', 'fire-eq-tech-moex-114-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依消防設備人員法規定，有關消防設備人員的業務及責任，下列敘述何者錯誤？', '["不容許他人借用本人名義執行業務", "消防設備士執行業務所製作之圖說及書表，應由本人簽名，並加蓋消防設備人員執業圖記", "執業消防設備士不得兼任公務員", "消防設備士應依消防法第7條第1項規定執行消防安全設備之設計、監造、測試及檢修業務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "175e5c35db4c", "answer_pdf_sha1": "f7df6e4dab9e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00071', 'fire-eq-tech', 'fire-eq-tech-moex-114-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依據消防法、公共危險物品及可燃性高壓氣體製造儲存處理場所設置標準暨安全管理辦法， 有關公共危險物品管制量規定，下列敘述何者錯誤？', '["第一種販賣場所：販賣裝於容器之六類物品，其數量未達管制量15倍之場所", "第二種販賣場所：販賣裝於容器之六類物品，其數量達管制量15倍以上，未達40倍之場所", "儲存六類物品達管制量以上者，應依其性質設置儲存場所儲存", "製造、儲存及處理公共危險物品合計達管制量20倍以上場所之管理權人，應遴用保安監督 人及保安檢查員"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "175e5c35db4c", "answer_pdf_sha1": "f7df6e4dab9e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00072', 'fire-eq-tech', 'fire-eq-tech-moex-114-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依各類場所消防安全設備設置標準，針對滅火設備水源容量之規定，下列敘述何者錯誤？', '["在裝置室內消防栓最多樓層之全部消防栓繼續放水20分鐘之水量以上。但該樓層內，全部 消防栓數量超過2支時，以2支計算之", "室外消防栓設備之水源容量，應在2具室外消防栓同時放水20分鐘之水量以上", "自動撒水設備之水源容量在使用放水型撒水頭時，採固定式者應在最大放水區域全部撒水 頭、採可動式者應在最大放水量撒水頭，繼續放射20分鐘之水量以上", "水霧滅火設備之水源容量，應保持20立方公尺以上。但放射區域在2區域以上者，應保持 40立方公尺以上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "175e5c35db4c", "answer_pdf_sha1": "f7df6e4dab9e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00073', 'fire-eq-tech', 'fire-eq-tech-moex-114-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依各類場所消防安全設備設置標準規定，二氧化碳滅火設備全區及局部放射方式之緊急電源， 應採用自用發電設備或蓄電池設備，其容量應能使該設備有效動作多少時間以上？', '["20分鐘", "30分鐘", "1小時", "2小時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "175e5c35db4c", "answer_pdf_sha1": "f7df6e4dab9e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00074', 'fire-eq-tech', 'fire-eq-tech-moex-114-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依各類場所消防安全設備設置標準規定，下列何處所得免設排煙設備？', '["特別安全梯間", "昇降機昇降路", "樓地板面積合計在500平方公尺以上之地下建築物", "緊急昇降機間"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:21+00:00", "source_pdf_sha1": "175e5c35db4c", "answer_pdf_sha1": "f7df6e4dab9e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114050", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "114", "exam_name": "114年專技人員高等考試大地工程技師考試分階段考試(第一階段考試)、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
